<script setup lang="ts">
import { onMounted, reactive, ref } from 'vue'
import { CheckCircle2, DownloadCloud, ExternalLink, LoaderCircle, RefreshCw, RotateCcw, ServerCog, ShieldAlert, ShieldCheck } from '@lucide/vue'
import { api, readableError, type HostJob, type HostStatus, type ReleaseInfo, type SystemInfo } from '../api'
import AppShell from '../components/AppShell.vue'

defineProps<{ theme: 'light' | 'dark' }>(); const emit = defineEmits<{ toggleTheme: [] }>()
const status = ref<HostStatus | null>(null); const system = ref<SystemInfo | null>(null); const releases = ref<ReleaseInfo[]>([]); const loading = ref(true); const busy = ref(false); const error = ref(''); const success = ref(''); const job = ref<HostJob | null>(null); const preview = ref<Record<string, unknown> | null>(null)
const network = reactive({ source_ip: '', udp_start: 40000, udp_end: 40099 }); const selectedVersion = ref('')
async function load() { loading.value = true; error.value = ''; try { const [host, info, settings] = await Promise.all([api.hostStatus(), api.systemInfo(), api.settings()]); status.value = host; system.value = info; network.udp_start = host.deployment?.udp_start ?? settings.udp_published_start; network.udp_end = host.deployment?.udp_end ?? settings.udp_published_end; network.source_ip = host.managed_firewall?.source_ip ?? '' } catch (reason) { error.value = readableError(reason) } finally { loading.value = false } }
async function firewallPreview() { error.value = ''; try { preview.value = await api.previewFirewall(network) } catch (reason) { error.value = readableError(reason) } }
async function firewallApply() { if (!confirm(`Apply the managed UFW rule for ${network.source_ip} and UDP ${network.udp_start}–${network.udp_end}?`)) return; busy.value = true; error.value = ''; try { await api.applyFirewall(network); success.value = 'Managed UFW rule applied.'; await load() } catch (reason) { error.value = readableError(reason) } finally { busy.value = false } }
async function pollJob(id: string) { for (let attempt = 0; attempt < 90; attempt += 1) { await new Promise(resolve => setTimeout(resolve, 2000)); try { job.value = await api.hostJob(id); if (job.value.status !== 'running') { if (job.value.status === 'succeeded') { success.value = `${job.value.operation} completed and passed health verification.`; await load() } else error.value = job.value.error ?? 'Host operation failed.'; busy.value = false; return } } catch { /* The app can briefly restart during deployment. */ } } error.value = 'The operation is still running. Refresh to check status.'; busy.value = false }
async function deployment() { if (!confirm('This recreates the WOLT app container with the new published UDP range and applies UFW. Continue?')) return; busy.value = true; error.value = ''; success.value = ''; try { const result = await api.updateDeployment(network); pollJob(result.job_id) } catch (reason) { error.value = readableError(reason); busy.value = false } }
async function checkReleases() { busy.value = true; error.value = ''; try { const result = await api.hostReleases(); releases.value = result.releases; selectedVersion.value = releases.value[0]?.name ?? '' } catch (reason) { error.value = readableError(reason) } finally { busy.value = false } }
async function upgrade() { if (!selectedVersion.value || !confirm(`Upgrade WOLT to ${selectedVersion.value}? Health verification and automatic rollback are enabled.`)) return; busy.value = true; error.value = ''; success.value = ''; try { const result = await api.upgradeHost(selectedVersion.value); pollJob(result.job_id) } catch (reason) { error.value = readableError(reason); busy.value = false } }
async function rollback() { if (!confirm('Roll back to the last recorded deployment?')) return; busy.value = true; error.value = ''; try { const result = await api.rollbackHost(); pollJob(result.job_id) } catch (reason) { error.value = readableError(reason); busy.value = false } }
onMounted(load)
</script>

<template><AppShell :theme="theme" @toggle-theme="emit('toggleTheme')"><section class="page-heading"><div><p class="eyebrow">ADMINISTRATION / HOST</p><h1>Host operations</h1><p>Manage the narrow host boundary without exposing Docker or root privileges to the WOLT container.</p></div><button class="secondary-button button-link" type="button" @click="load"><RefreshCw :size="15" /> Refresh</button></section><p v-if="error" class="form-error page-error" role="alert">{{ error }}</p><p v-if="success" class="form-success page-message"><CheckCircle2 :size="15" /> {{ success }}</p><section v-if="loading" class="panel loading-panel"><LoaderCircle class="spin" /> Connecting to Host Agent…</section><section v-else-if="!status" class="panel host-agent-empty"><ShieldAlert :size="30" /><h2>Restricted Host Agent required</h2><p>Install it once on the Docker host, then recreate WOLT with the generated Unix-socket override.</p><code>sudo ./scripts/install-host-agent.sh /data/WOLT</code></section><div v-else class="settings-stack"><section class="host-status-grid"><article class="panel metric-card"><span class="metric-title"><ServerCog :size="16" /> Host Agent</span><strong>v{{ status.agent_version }}</strong><p>Unix socket authenticated</p></article><article class="panel metric-card"><span class="metric-title"><ShieldCheck :size="16" /> UFW</span><strong>{{ status.ufw_active ? 'Active' : 'Inactive' }}</strong><p>{{ status.ufw_available ? 'Command available' : 'Not installed' }}</p></article><article class="panel metric-card"><span class="metric-title"><DownloadCloud :size="16" /> Image</span><strong>{{ system?.version }}</strong><p>{{ status.cosign_available ? 'Cosign verification ready' : 'Cosign required for upgrades' }}</p></article></section><div class="settings-layout"><section class="panel settings-card"><header><ShieldCheck :size="20" /><div><h2>Managed UDP ingress</h2><p>Only one WOLT-labelled UFW rule is managed. Existing unrelated rules are untouched.</p></div></header><div class="operations-form"><label>Allowed PAM / Guacamole source IP<input v-model.trim="network.source_ip" required placeholder="192.168.89.67" /></label><div class="form-row equal"><label>Published start<input v-model.number="network.udp_start" type="number" min="1024" max="65535" /></label><label>Published end<input v-model.number="network.udp_end" type="number" min="1024" max="65535" /></label></div><div class="host-action-row"><button class="secondary-button" :disabled="busy" type="button" @click="firewallPreview">Preview</button><button class="secondary-button" :disabled="busy || !network.source_ip" type="button" @click="firewallApply">Apply UFW only</button><button class="primary-button" :disabled="busy || !network.source_ip" type="button" @click="deployment">Apply range & recreate</button></div><pre v-if="preview" class="host-preview">{{ JSON.stringify(preview, null, 2) }}</pre></div></section><aside class="panel settings-card"><header><DownloadCloud :size="20" /><div><h2>Verified upgrade</h2><p>Verify the official GitHub Actions signature, pin its digest, recreate, health-check, and automatically roll back on failure.</p></div></header><div class="operations-form"><div v-if="!status.cosign_available" class="retention-note roadmap-note"><ShieldAlert :size="16" /><p>Install Cosign from Sigstore at <code>/usr/local/bin/cosign</code> to enable signed upgrades.</p></div><button class="secondary-button button-link" :disabled="busy" type="button" @click="checkReleases"><RefreshCw :size="14" /> Check Docker Hub</button><label>Release<select v-model="selectedVersion" :disabled="!releases.length"><option value="">Select a release</option><option v-for="release in releases" :key="release.name" :value="release.name">{{ release.name }}</option></select></label><button class="primary-button button-link" :disabled="busy || !selectedVersion || !status.cosign_available" type="button" @click="upgrade"><DownloadCloud :size="15" /> Verify signature & upgrade</button><button class="secondary-button button-link danger-text" :disabled="busy" type="button" @click="rollback"><RotateCcw :size="15" /> Roll back last deployment</button><p v-if="job" class="host-job"><LoaderCircle v-if="job.status === 'running'" class="spin" :size="15" /> Job {{ job.operation }}: {{ job.status }}</p><a class="form-link" href="https://hub.docker.com/r/alirezasayyari/wolt/tags" target="_blank" rel="noreferrer">View published tags <ExternalLink :size="13" /></a></div></aside></div></div></AppShell></template>
